  ('dietitian-moex-10914', 'dietitian', 'dietitian-moex-094-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '台灣曾發生過多氯聯苯中毒，是屬於： 米糠油酸敗引起    米中過高農藥引起 防腐劑添加不當引起    本身是熱觸媒污染到油脂中引起', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "824a01d7b78c", "answer_pdf_sha1": "709e2e5741d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
