  ('dietitian-moex-10917', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '利用音叉試驗腳踝及膝部，可測出下列那個營養素缺乏？ 維生素B 維生素B 維生素B 葉酸', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10918', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '6  12', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10919', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在諮詢過程中，下列何者是一個營養諮詢者不適合的行為？ 了解服務對象無力解決問題，而代其解決  能隨時配合被諮詢者調整飲食計畫步驟的意願 能傾聽被諮詢者訴說    能體會被諮詢者的問題情境', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10920', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在營養諮詢過程中，假如被諮詢者面臨生活上的重大變遷，諮詢者採用下列那一種措施最適合？ 幫助被諮詢者應付生活變遷所產生的問題  暫時中止諮詢，等被諮詢者處理完變遷問題再重新開始 暫時忘記生活上的變遷，仍繼續遵循飲食計畫  提供獎勵品，鼓勵被諮詢者繼續接受諮詢', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10921', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '行政院衛生署規定，自民國91年9月起，市售包裝食品營養標示之基準固體，每一份量須以什麼單位標示？ 每100公克  每500公克  每1公斤  每50公克', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10922', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '為預防心血管疾病，美國國家膽固醇教育計畫建議成人血總膽固醇與LDL-膽固醇之濃度宜為多少？ 血總膽固醇 < 240 mg/dL；LDL-膽固醇 < 150 mg/dL  血總膽固醇 < 150 mg/dL；LDL-膽固醇 < 240 mg/dL 血總膽固醇 < 200 mg/dL；LDL-膽固醇 < 130 mg/dL  血總膽固醇 < 200 mg/dL；LDL-膽固醇 < 150 mg/dL', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10923', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列關於腰臀圍比之敘述，何者錯誤？ 可用來判定皮下脂肪厚度    與腹部脂肪之堆積有極高之相關性 男性之正常範圍上限較女性高  若大於1，會增加高血壓、高血糖之罹病及死亡率', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
